#!/usr/bin/env Rscript
# 01_data_prep.R: Sensitivity Analysis Aggregation
# Aggregates results from T013b (sensitivity loop) to generate Power vs. Delta mapping.
#
# Input: data/processed/sensitivity_datasets/ (generated by T013b)
# Output: results/processed/sensitivity_curve_data.csv, results/plots/sensitivity_analysis.png

# Load required libraries
library(dplyr)
library(ggplot2)
library(tidyr)
library(purrr)
library(lme4)
library(lmerTest)

# Source utility functions
source("code/utils.R")

# Load configuration for random seed
config <- load_config("code/config.yaml")
set_random_seed(config$seed)

# Define paths
sensitivity_dir <- "data/processed/sensitivity_datasets"
output_csv <- "results/processed/sensitivity_curve_data.csv"
output_plot <- "results/plots/sensitivity_analysis.png"

# Ensure output directories exist
dir.create("results/processed", showWarnings = FALSE, recursive = TRUE)
dir.create("results/plots", showWarnings = FALSE, recursive = TRUE)

# Verify input directory exists
if (!dir.exists(sensitivity_dir)) {
  stop("Sensitivity datasets directory not found: ", sensitivity_dir,
       ". Ensure T013b has been executed successfully.")
}

# List all CSV files in the sensitivity directory
csv_files <- list.files(sensitivity_dir, pattern = "\\.csv$", full.names = TRUE)

if (length(csv_files) == 0) {
  stop("No CSV files found in ", sensitivity_dir, ". Ensure T013b generated data.")
}

cat("Found", length(csv_files), "sensitivity dataset files to aggregate.\n")

# Function to analyze a single dataset and extract power
analyze_dataset <- function(file_path) {
  tryCatch({
    df <- read.csv(file_path)

    # Extract delta value from filename or assume it's in the data
    # Assuming file naming: sensitivity_delta_X.csv or similar
    # If not in filename, we expect a 'delta' column in the CSV
    if ("delta" %in% colnames(df)) {
      delta_val <- unique(df$delta)
      if (length(delta_val) > 1) stop("Multiple delta values in one file: ", file_path)
    } else {
      # Parse from filename if column missing (fallback)
      filename <- basename(file_path)
      delta_match <- regmatches(filename, regexpr("delta[=._-]([0-9.]+)", filename))
      if (length(delta_match) > 0) {
        delta_val <- as.numeric(gsub(".*[=._-]([0-9.]+)$", "\\1", delta_match))
      } else {
        warning("Could not determine delta for ", file_path, "; skipping.")
        return(NULL)
      }
    }

    # Fit mixed-effects model: severity_rating ~ framing_condition + (1|stimulus_id)
    # Check for sufficient data
    if (nrow(df) < 10) {
      warning("Insufficient data in ", file_path, "; skipping.")
      return(NULL)
    }

    model <- lmer(severity_rating ~ framing_condition + (1 | stimulus_id), data = df)

    # Extract p-value for framing_condition
    # lmerTest provides p-values in summary
    p_val <- summary(model)$coefficients["framing_conditionfact", "Pr(>|t|)"]

    # Power is 1 - beta. Here we treat p < 0.05 as "detected effect"
    # Since we are simulating, "Power" for this specific delta is the proportion of times
    # we detect significance. However, T013b likely generated ONE dataset per delta.
    # If T013b generated multiple replicates per delta, we would aggregate here.
    # Assuming T013b generated 1 dataset per delta for this specific task scope:
    # We record the p-value. If multiple replicates exist, we calculate power as mean(p < 0.05).
    #
    # To be robust: If the file contains multiple rows per condition but only one dataset,
    # the p-value is the result for that specific simulation run.
    # The "Power vs Delta" curve usually requires averaging over many replicates.
    # If T013b only did one run per delta, this is a "Significance vs Delta" plot.
    # We will calculate the binary significance indicator.

    significant <- ifelse(!is.na(p_val) && p_val < 0.05, 1, 0)

    data.frame(
      delta = delta_val,
      p_value = p_val,
      significant = significant
    )
  }, error = function(e) {
    warning("Error processing ", file_path, ": ", e$message)
    return(NULL)
  })
}

# Process all files
results_list <- lapply(csv_files, analyze_dataset)
results_df <- bind_rows(results_list)

if (nrow(results_df) == 0) {
  stop("No valid results could be extracted from sensitivity datasets.")
}

# Sort by delta
results_df <- results_df %>% arrange(delta)

# Calculate cumulative power (if multiple replicates per delta existed, this would average)
# If only one per delta, we map 0/1 directly.
# To make a smooth curve, we might want to group by delta and calculate mean(significant)
# assuming T013b might have generated multiple files per delta (e.g., replicates).
# If T013b generated unique files for unique deltas, this group_by is effectively identity.

power_curve <- results_df %>%
  group_by(delta) %>%
  summarise(
    power = mean(significant),
    mean_p = mean(p_value, na.rm = TRUE),
    n_replicates = n()
  ) %>%
  arrange(delta)

# Save CSV
write.csv(power_curve, output_csv, row.names = FALSE)
cat("Saved sensitivity curve data to:", output_csv, "\n")

# Generate Visualization
p <- ggplot(power_curve, aes(x = delta, y = power)) +
  geom_point(size = 3, color = "steelblue") +
  geom_line(color = "steelblue", linewidth = 1) +
  geom_hline(yintercept = 0.80, linetype = "dashed", color = "red", alpha = 0.7) +
  labs(
    title = "Statistical Power vs. Effect Size (Delta)",
    subtitle = "Mixed-effects model: severity_rating ~ framing_condition + (1|stimulus_id)",
    x = "Effect Size (Delta)",
    y = "Power (Proportion Significant)"
  ) +
  theme_minimal() +
  theme(
    plot.title = element_text(face = "bold", hjust = 0.5),
    plot.subtitle = element_text(hjust = 0.5)
  )

ggsave(output_plot, plot = p, width = 8, height = 6, dpi = 300)
cat("Saved sensitivity analysis plot to:", output_plot, "\n")

cat("Task T013c completed successfully.\n")
